body.script:
test(function() {
  const t1 = document.getElementById('t1');
  assert_equals(getComputedStyle(t1).color, 'rgb(0, 128, 0)');
  assert_not_background_color(document.documentElement, RED);
  assert_not_background_color(document.body, RED);
}, 'Impossible rules (* html, * :root) should not match');
